def solve(sequence, database, e_value_threshold=0.001):
    from Bio.Blast import NCBIWWW, NCBIXML

    # Validate inputs vs contract
    if not isinstance(sequence, str) or not isinstance(database, str):
        raise ValueError("Sequence and database must be strings.")

    if not sequence:
        raise ValueError("Sequence cannot be empty.")

    if not database:
        raise ValueError("Database cannot be empty.")

    # Implement core logic
    result_handle = NCBIWWW.qblast("blastn", database, sequence, expect=e_value_threshold)
    blast_records = NCBIXML.parse(result_handle)

    # Check edge cases
    results = []
    for blast_record in blast_records:
        if blast_record.alignments:
            for alignment in blast_record.alignments:
                for hsp in alignment.hsps:
                    results.append({
                        'title': alignment.title,
                        'length': alignment.length,
                        'score': hsp.score,
                        'e_value': hsp.expect,
                        'query_start': hsp.query_start,
                        'query_end': hsp.query_end,
                        'match': hsp.match,
                    })

    return results if results else None
